    "completion": "class Mergesort \n{ \n    void merge(int arr[], int l, int m, int r) \n    { \n        int n1 = m - l + 1; \n        int n2 = r - m; \n  \n        int L[] = new int[n1]; \n        int R[] = new int[n2]; \n  \n        for (int i = 0; i < n1; ++i) \n            L[i] = arr[l + i]; \n        for (int j = 0; j < n2; ++j) \n            R[j] = arr[m + 1 + j]; \n  \n        int i = 0, j = 0; \n  \n        int k = l; \n        while (i < n1 && j < n2) { \n            if (L[i] <= R[j]) { \n                arr[k] = L[i]; \n                i++; \n            } \n            else { \n                arr[k] = R[j]; \n                j++; \n            } \n            k++; \n        } \n  \n        while (i < n1) { \n            arr[k] = L[i]; \n            i++; \n            k++; \n        } \n  \n        while (j < n2) { \n            arr[k] = R[j]; \n            j++; \n            k++; \n        } \n    } \n  \n    void sort(int arr[], int l, int r) \n    { \n        if (l < r) { \n            int m = (l + r) / 2; \n  \n            sort(arr, l, m); \n            sort(arr, m + 1, r); \n  \n            merge(arr, l, m, r); \n        } \n    } \n}",
