    "prompt": "Implement a LRU cache in Java\n",
    "completion": "import java.util.HashMap;\n \npublic class LRUCache { \n  \n    // Custom Doubly Linked List \n    static class CacheNode { \n        CacheNode prev; \n        CacheNode next; \n        int key; \n        int value; \n    } \n  \n    // Map containing the Keys \n    private HashMap<Integer, CacheNode> map \n        = new HashMap<Integer, CacheNode>(); \n  \n    // Maximum number of elements in the cache \n    private int capacity; \n  \n    // Current size \n    private int size; \n  \n    // Head of the DLL \n    private CacheNode head; \n  \n    // Tail of the DLL \n    private CacheNode tail; \n  \n    public LRUCache(int capacity) { \n        this.capacity = capacity; \n        this.size = 0; \n    } \n  \n    // Lookup a key in the cache \n    public int get(int key) { \n  \n        // Return -1 if no such key exists \n        if (!map.containsKey(key)) { \n            return -1; \n        } \n  \n        // Get the node \n        CacheNode node = map.get(key); \n  \n        // Delete the node \n        removeNode(node); \n  \n        // Put it at the head \n        addAtHead(node); \n  \n        // Return its value \n        return node.value; \n    } \n  \n    // Add a new node to the cache \n    public void put(int key, int value) { \n        CacheNode node = new CacheNode(); \n        node.key = key; \n        node.value = value; \n  \n        // Check if the node is already present \n        if (map.containsKey(key)) { \n            CacheNode oldNode = map.get(key); \n            removeNode(oldNode); \n            addAtHead(node); \n            map.put(key, node); \n        } else { \n            // Add at the front of the list \n            if (size == capacity) { \n                // Delete the last node \n                map.remove(tail.key); \n                removeNode(tail); \n            } \n            addAtHead(node); \n            map.put(key, node); \n        } \n    } \n  \n    // Remove a node from the list \n    public void removeNode(CacheNode node) { \n        if (node.prev != null) { \n            node.prev.next = node.next; \n        } else { \n            head = node.next; \n        } \n  \n        if (node.next != null) { \n            node.next.prev = node.prev; \n        } else { \n            tail = node.prev; \n        } \n  \n        size--; \n    } \n  \n    // Put a node at the front of the list \n    public void addAtHead(CacheNode node) { \n        node.next = null; \n        node.prev = null; \n  \n        if (head == null) { \n            head = node; \n            tail = node; \n        } else { \n            node.next = head; \n            head.prev = node; \n            head = node; \n        } \n  \n        size++; \n    } \n}",
